class Solution:
    def maxAncestorDiff(self, root):
        """
        :type root: Optional[TreeNode]
        :rtype: int
        """
        def dfs(node, min_val, max_val):
            if not node:
                return max_val - min_val

            # Update min and max seen on path from root to node
            min_val = min(min_val, node.val)
            max_val = max(max_val, node.val)

            # Current max difference at this node
            current_diff = max_val - min_val

            # Recurse to children
            left_diff = dfs(node.left, min_val, max_val)
            right_diff = dfs(node.right, min_val, max_val)

            return max(current_diff, left_diff, right_diff)

        return dfs(root, root.val, root.val)
